let allSkills = [];
let vacancyCount = 0;

console.log('=== DEBUG: INPUT DATA ===');
console.log('Input items count:', $input.all().length);

for (const item of $input.all()) {
  console.log('Processing item:', item);

  // Варианты: текст может быть в output или result
  const text = item.json.text || item.json.output || item.json.result;

  if (text && text.length > 0) {
    vacancyCount++;

    const skillsArray = text.split(',')
      .map(skill => skill.trim())
      .filter(skill => skill.length > 0 && skill.toLowerCase() !== 'devops');

    console.log(`Вакансия ${vacancyCount}:`, skillsArray);
    allSkills = allSkills.concat(skillsArray);
  }
}

console.log('Всего навыков собрано:', allSkills.length);

const skillCount = {};
allSkills.forEach(skill => {
  const normalized = skill.toLowerCase().trim();
  skillCount[normalized] = (skillCount[normalized] || 0) + 1;
});

const sortedSkills = Object.entries(skillCount)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 15)
  .map(([skill, count]) => [skill.charAt(0).toUpperCase() + skill.slice(1), count]);

return [{ 
  sortedSkills,
  totalVacancies: vacancyCount
}];

